import { createContext, useContext, useEffect, useState } from 'react'
import { supabase } from '@/lib/supabase'

interface UserProfile {
  id: string
  full_name: string
  role: 'admin' | 'staff' | 'delivery'
}

interface AuthContextType {
  user: any | null
  profile: UserProfile | null
  loading: boolean
  signOut: () => Promise<void>
}

const AuthContext = createContext<AuthContextType>({
  user: null,
  profile: null,
  loading: true,
  signOut: async () => {}
})

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<any | null>(null)
  const [profile, setProfile] = useState<UserProfile | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    // Check active sessions and sets the user
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) {
        setUser(session.user)
        fetchProfile(session.user.id)
      } else {
        setLoading(false)
      }
    })

    // Listen for changes on auth state (in, out, etc.)
    const {
      data: { subscription }
    } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        setUser(session.user)
        fetchProfile(session.user.id)
      } else {
        setUser(null)
        setProfile(null)
        setLoading(false)
      }
    })

    return () => subscription.unsubscribe()
  }, [])

  const fetchProfile = async (userId: string) => {
    try {
      const { data, error } = await supabase.from('profiles').select('*').eq('id', userId).single()

      if (!error && data) {
        setProfile(data as UserProfile)
      }
    } catch (err) {
      console.error('Error fetching profile:', err)
    } finally {
      setLoading(false)
    }
  }

  const signOut = async () => {
    await supabase.auth.signOut()
    setUser(null)
    setProfile(null)
  }

  return (
    <AuthContext.Provider value={{ user, profile, loading, signOut }}>
      {!loading && children}
    </AuthContext.Provider>
  )
}

export const useAuth = () => {
  return useContext(AuthContext)
}

import { useState } from 'react'
import { supabase } from '@/lib/supabase'
import { useNavigate } from 'react-router-dom'

export default function Login() {
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [error, setError] = useState('')
  const [loading, setLoading] = useState(false)
  const navigate = useNavigate()

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault()
    setLoading(true)
    setError('')

    try {
      const { error } = await supabase.auth.signInWithPassword({
        email,
        password
      })

      if (error) throw error

      // Navigation is handled by AuthContext trigger -> ProtectedRoute
      navigate('/')
    } catch (err: any) {
      setError(err.message || 'Error al iniciar sesión')
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="flex items-center justify-center min-h-screen bg-background-dark p-4 font-display">
      <div className="w-full max-w-sm bg-surface-dark border border-border-dark rounded-2xl p-8 shadow-2xl relative overflow-hidden">
        {/* Decorative elements */}
        <div className="absolute top-0 right-0 p-4 opacity-10">
          <span className="material-symbols-outlined text-white text-6xl">flash_on</span>
        </div>

        <h1 className="text-3xl font-black text-white mb-2 text-center tracking-tight">
          Comanda<span className="text-primary">Flash</span>
        </h1>
        <p className="text-text-secondary text-sm text-center mb-8">
          Ingresa tus credenciales para continuar
        </p>

        {error && (
          <div className="mb-4 bg-red-500/10 border border-red-500/50 text-red-500 text-sm p-3 rounded-xl font-medium text-center">
            {error}
          </div>
        )}

        <form onSubmit={handleLogin} className="space-y-4">
          <div>
            <label className="block text-xs font-bold text-text-secondary mb-1.5 uppercase tracking-wider">
              Correo Electrónico
            </label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              className="w-full bg-background-dark border border-border-dark text-white rounded-xl p-3 focus:ring-1 focus:ring-primary focus:border-primary outline-none transition-all placeholder:text-slate-600"
              placeholder="tu@correo.com"
            />
          </div>

          <div>
            <label className="block text-xs font-bold text-text-secondary mb-1.5 uppercase tracking-wider">
              Contraseña
            </label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              className="w-full bg-background-dark border border-border-dark text-white rounded-xl p-3 focus:ring-1 focus:ring-primary focus:border-primary outline-none transition-all placeholder:text-slate-600"
              placeholder="••••••••"
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            className="w-full bg-primary hover:bg-orange-600 focus:ring-4 focus:ring-primary/20 text-white font-bold rounded-xl py-3.5 mt-4 transition-all flex items-center justify-center gap-2 group disabled:opacity-70"
          >
            {loading ? (
              <div className="animate-spin rounded-full h-5 w-5 border-t-2 border-b-2 border-white"></div>
            ) : (
              <>
                Ingresar
                <span className="material-symbols-outlined text-lg group-hover:translate-x-1 transition-transform">
                  arrow_forward
                </span>
              </>
            )}
          </button>
        </form>

        <div className="mt-8 pt-6 border-t border-border-dark/50 text-center">
          <p className="text-xs text-text-muted">
            Para desarrollo, usa las cuentas definidas en el panel de Supabase.
          </p>
        </div>
      </div>
    </div>
  )
}

import { useState } from 'react'
import { useFormik } from 'formik'
import { supabase } from '@/lib/supabase'
import { useNavigate } from 'react-router-dom'
import { MapPin, ShoppingBag, Plus, Minus, Tag, CheckCircle2 } from 'lucide-react'
import { parseLocationUrl } from '@/utils/locationParser'

// Hardcoded for MVP, ideally fetched from DB
const PRODUCTS = [
  { id: '1', name: 'Pizza Margherita', price: 1200 },
  { id: '2', name: 'Hamburguesa Completa', price: 950 },
  { id: '3', name: 'Papas Fritas', price: 500 },
  { id: '4', name: 'Gaseosa 500ml', price: 300 }
]

export default function CreateOrder() {
  const navigate = useNavigate()
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  const formik = useFormik({
    initialValues: {
      customer_name: '',
      address_text: '',
      location_url: '',
      is_paid: false,
      items: [] as { product_id: string; quantity: number; price: number }[]
    },
    onSubmit: async (values) => {
      if (values.items.length === 0) {
        setError('Debes agregar al menos un producto al pedido.')
        return
      }
      setLoading(true)
      setError(null)

      try {
        // 1. Calculate totals and parse location
        const coords = parseLocationUrl(values.location_url)
        const total_amount = values.items.reduce((sum, item) => sum + item.price * item.quantity, 0)

        // 2. Insert Order
        const { data: orderData, error: orderError } = await supabase
          .from('orders')
          .insert({
            customer_name: values.customer_name,
            address_text: values.address_text,
            location_url: values.location_url,
            lat: coords?.lat,
            lng: coords?.lng,
            is_paid: values.is_paid,
            total_amount: total_amount,
            status: 'pending'
          })
          .select()
          .single()

        if (orderError) throw orderError

        // 3. Insert Items (Dummy logic for now since we don't strictly have an items table in the exact prompt except order_items)
        // If 'order_items' table exists:
        const orderItems = values.items.map((i) => ({
          order_id: orderData.id,
          product_id: null, // Hardcoded IDs aren't real UUIDs in DB, so we'd normally lookup
          quantity: i.quantity,
          subtotal: i.price * i.quantity
        }))

        // Optional: await supabase.from('order_items').insert(orderItems)
        // We will skip inserting items in the DB for this MVP if the table isn't fully synced with these fake IDs

        navigate('/comanda')
      } catch (err: unknown) {
        if (err instanceof Error) {
          setError(err.message)
        } else {
          setError('Error al crear el pedido')
        }
      } finally {
        setLoading(false)
      }
    }
  })

  // Helper for items
  const handleItemToggle = (product: (typeof PRODUCTS)[0]) => {
    const existing = formik.values.items.find((i) => i.product_id === product.id)
    if (existing) {
      formik.setFieldValue(
        'items',
        formik.values.items.map((i) =>
          i.product_id === product.id ? { ...i, quantity: i.quantity + 1 } : i
        )
      )
    } else {
      formik.setFieldValue('items', [
        ...formik.values.items,
        { product_id: product.id, quantity: 1, price: product.price }
      ])
    }
  }

  const handleItemRemove = (productId: string) => {
    const existing = formik.values.items.find((i) => i.product_id === productId)
    if (existing && existing.quantity > 1) {
      formik.setFieldValue(
        'items',
        formik.values.items.map((i) =>
          i.product_id === productId ? { ...i, quantity: i.quantity - 1 } : i
        )
      )
    } else {
      formik.setFieldValue(
        'items',
        formik.values.items.filter((i) => i.product_id !== productId)
      )
    }
  }

  const getTotal = () =>
    formik.values.items.reduce((sum, item) => sum + item.price * item.quantity, 0)

  return (
    <div className="h-full flex flex-col overflow-y-auto pb-24">
      <div className="p-4 bg-surface-dark sticky top-0 z-10 border-b border-border-dark flex justify-between items-center shadow-sm">
        <h1 className="text-xl font-bold text-white flex items-center gap-2">
          <ShoppingBag className="w-5 h-5 text-primary" />
          Nuevo Pedido
        </h1>
      </div>

      <div className="p-4 space-y-6">
        {error && (
          <div className="p-4 bg-red-500/10 border border-red-500/50 rounded-2xl text-red-500 text-sm font-medium">
            {error}
          </div>
        )}

        <form onSubmit={formik.handleSubmit} className="space-y-6">
          {/* Customer Details */}
          <section className="bg-surface-dark p-5 rounded-3xl border border-border-dark space-y-4">
            <h2 className="text-sm font-bold text-text-secondary uppercase tracking-wider mb-2">
              Datos del Cliente
            </h2>

            <div>
              <label className="block text-xs font-medium text-text-muted mb-1.5 ml-1">
                Nombre Completo
              </label>
              <input
                name="customer_name"
                onChange={formik.handleChange}
                value={formik.values.customer_name}
                className="w-full bg-background-dark border border-border-dark text-white rounded-2xl px-4 py-3.5 focus:ring-1 focus:ring-primary focus:border-primary outline-none transition-all placeholder:text-slate-600"
                placeholder="Ej. Juan Pérez"
                required
              />
            </div>

            <div>
              <label className="block text-xs font-medium text-text-muted mb-1.5 ml-1">
                Dirección Física
              </label>
              <input
                name="address_text"
                onChange={formik.handleChange}
                value={formik.values.address_text}
                className="w-full bg-background-dark border border-border-dark text-white rounded-2xl px-4 py-3.5 focus:ring-1 focus:ring-primary focus:border-primary outline-none transition-all placeholder:text-slate-600"
                placeholder="Calle Falsa 123"
                required
              />
            </div>

            <div>
              <label className="block text-xs font-medium text-text-muted mb-1.5 ml-1 flex items-center gap-1.5">
                <MapPin className="w-3.5 h-3.5" /> Link de Google Maps / WhatsApp
              </label>
              <input
                name="location_url"
                onChange={formik.handleChange}
                value={formik.values.location_url}
                className="w-full bg-background-dark border border-border-dark text-white rounded-2xl px-4 py-3.5 focus:ring-1 focus:ring-primary focus:border-primary outline-none transition-all placeholder:text-slate-600 font-mono text-sm"
                placeholder="https://maps.app.goo.gl/..."
              />
              {parseLocationUrl(formik.values.location_url) && (
                <p className="text-xs text-green-500 mt-2 ml-1 flex items-center gap-1">
                  <CheckCircle2 className="w-3 h-3" /> Coordenadas extraídas correctamente
                </p>
              )}
            </div>
          </section>

          {/* Product Selection */}
          <section className="bg-surface-dark p-5 rounded-3xl border border-border-dark space-y-4">
            <h2 className="text-sm font-bold text-text-secondary uppercase tracking-wider mb-2 flex items-center gap-2">
              <Tag className="w-4 h-4" /> Productos
            </h2>

            <div className="grid gap-3">
              {PRODUCTS.map((prod) => {
                const item = formik.values.items.find((i) => i.product_id === prod.id)
                const qty = item?.quantity || 0

                return (
                  <div
                    key={prod.id}
                    className={`flex items-center justify-between p-3 rounded-2xl border transition-colors ${qty > 0 ? 'bg-primary/5 border-primary/30' : 'bg-background-dark border-border-dark'}`}
                  >
                    <div>
                      <p className="font-medium text-white text-sm">{prod.name}</p>
                      <p className="text-text-secondary text-xs">${prod.price}</p>
                    </div>

                    <div className="flex items-center gap-3">
                      {qty > 0 && (
                        <>
                          <button
                            type="button"
                            onClick={() => handleItemRemove(prod.id)}
                            className="w-8 h-8 rounded-full bg-surface-dark border border-border-dark flex items-center justify-center text-text-secondary hover:text-white"
                          >
                            <Minus className="w-4 h-4" />
                          </button>
                          <span className="font-bold text-white w-4 text-center">{qty}</span>
                        </>
                      )}
                      <button
                        type="button"
                        onClick={() => handleItemToggle(prod)}
                        className={`w-8 h-8 rounded-full flex items-center justify-center transition-colors ${qty > 0 ? 'bg-primary text-white' : 'bg-surface-dark border border-border-dark text-text-secondary hover:text-white'}`}
                      >
                        <Plus className="w-4 h-4" />
                      </button>
                    </div>
                  </div>
                )
              })}
            </div>
          </section>

          {/* Payment & Submit */}
          <section className="bg-surface-dark p-5 rounded-3xl border border-border-dark space-y-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="font-bold text-white">Estado del Pago</p>
                <p className="text-xs text-text-muted">¿El cliente ya abonó el pedido?</p>
              </div>
              <label className="relative inline-flex items-center cursor-pointer">
                <input
                  type="checkbox"
                  name="is_paid"
                  onChange={formik.handleChange}
                  checked={formik.values.is_paid}
                  className="sr-only peer"
                />
                <div className="w-14 h-7 bg-background-dark border-border-dark peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-text-secondary peer-checked:after:bg-white after:border-gray-300 after:border after:rounded-full after:h-6 after:w-6 after:transition-all peer-checked:bg-primary"></div>
              </label>
            </div>

            <div className="pt-4 border-t border-border-dark flex items-end justify-between">
              <span className="text-text-secondary font-medium">Total</span>
              <span className="text-3xl font-black text-white tracking-tighter">${getTotal()}</span>
            </div>

            <button
              type="submit"
              disabled={loading || formik.values.items.length === 0}
              className="w-full bg-primary hover:bg-orange-600 disabled:opacity-50 disabled:hover:bg-primary focus:ring-4 focus:ring-primary/20 text-white font-bold rounded-2xl py-4 transition-all flex items-center justify-center gap-2 group shadow-xl shadow-primary/20"
            >
              {loading ? (
                <div className="animate-spin rounded-full h-5 w-5 border-t-2 border-b-2 border-white"></div>
              ) : (
                <>
                  <CheckCircle2 className="w-5 h-5 group-hover:scale-110 transition-transform" />
                  Confirmar Pedido
                </>
              )}
            </button>
          </section>
        </form>
      </div>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { supabase } from '@/lib/supabase'
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import type { LucideIcon } from 'lucide-react'
import { ClipboardList, ChefHat, CheckCircle2, RotateCcw, Package, Clock } from 'lucide-react'

type OrderStatus =
  | 'pending'
  | 'preparing'
  | 'ready'
  | 'shipping'
  | 'delivered'
  | 'cancelled'
  | 'failed'

interface Order {
  id: string
  customer_name: string
  address_text: string | null
  status: OrderStatus
  total_amount: number | null
  created_at: string
}

const fetchOrders = async (): Promise<Order[]> => {
  const { data, error } = await supabase
    .from('orders')
    .select('*')
    .order('created_at', { ascending: false })

  if (error) throw new Error(error.message)
  return data
}

export default function DigitalComanda() {
  const [activeTab, setActiveTab] = useState<'pending' | 'ready' | 'history'>('pending')
  const queryClient = useQueryClient()

  const {
    data: orders = [],
    isLoading,
    isError
  } = useQuery({
    queryKey: ['orders'],
    queryFn: fetchOrders
  })

  // Set up Supabase Realtime specifically to invalidate React Query cache
  useEffect(() => {
    const channel = supabase
      .channel('public:orders')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'orders' }, () => {
        // Invalidate and refetch
        queryClient.invalidateQueries({ queryKey: ['orders'] })
      })
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [queryClient])

  const updateStatusMutation = useMutation({
    mutationFn: async ({ id, newStatus }: { id: string; newStatus: OrderStatus }) => {
      const { error } = await supabase.from('orders').update({ status: newStatus }).eq('id', id)
      if (error) throw new Error(error.message)
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['orders'] })
    }
  })

  const handleUpdateStatus = (id: string, newStatus: OrderStatus) => {
    updateStatusMutation.mutate({ id, newStatus })
  }

  const filteredOrders = orders.filter((o) => {
    if (activeTab === 'pending') return o.status === 'pending' || o.status === 'preparing'
    if (activeTab === 'ready') return o.status === 'ready'
    if (activeTab === 'history')
      return ['shipping', 'delivered', 'cancelled', 'failed'].includes(o.status)
    return false
  })

  const TabButton = ({
    id,
    label,
    icon: Icon
  }: {
    id: 'pending' | 'ready' | 'history'
    label: string
    icon: LucideIcon
  }) => (
    <button
      onClick={() => setActiveTab(id)}
      className="relative flex flex-col items-center justify-center pb-3 flex-1 group"
    >
      <div
        className={`flex items-center gap-1.5 ${activeTab === id ? 'text-primary' : 'text-text-secondary group-hover:text-white transition-colors'}`}
      >
        <Icon className="w-4 h-4" />
        <span className="text-sm font-bold leading-normal tracking-wide">{label}</span>
      </div>
      {activeTab === id && (
        <div className="absolute bottom-0 w-full h-[3px] bg-primary rounded-t-full shadow-[0_0_10px_rgba(238,124,43,0.5)]"></div>
      )}
    </button>
  )

  return (
    <div className="relative flex min-h-full w-full flex-col overflow-x-hidden p-4">
      {/* Header / Title Area */}
      <div className="mb-6 mt-2 flex items-center gap-3 px-2">
        <div className="w-10 h-10 rounded-full bg-primary/10 flex items-center justify-center">
          <ClipboardList className="w-5 h-5 text-primary" />
        </div>
        <div>
          <h1 className="text-xl font-black text-white tracking-tight">Comanda Digital</h1>
          <p className="text-xs text-text-muted mt-0.5">Gestión de órdenes en tiempo real</p>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-border-dark w-full mb-6 shrink-0 pt-2">
        <TabButton id="pending" label="Pendientes" icon={Clock} />
        <TabButton id="ready" label="Listos" icon={CheckCircle2} />
        <TabButton id="history" label="Historial" icon={RotateCcw} />
      </div>

      {/* Main Content: Orders List */}
      <div className="flex flex-col gap-4 overflow-y-auto pb-24 px-1">
        {isLoading && (
          <div className="flex justify-center py-10">
            <div className="animate-spin rounded-full h-8 w-8 border-t-2 border-b-2 border-primary"></div>
          </div>
        )}

        {isError && (
          <div className="p-4 bg-red-500/10 border border-red-500/50 rounded-2xl text-red-500 text-sm font-medium text-center">
            Error al cargar las órdenes. Inténtalo de nuevo.
          </div>
        )}

        {!isLoading && !isError && filteredOrders.length === 0 && (
          <div className="flex flex-col items-center justify-center text-text-muted py-16 px-4 bg-surface-dark/50 rounded-3xl border border-dashed border-border-dark">
            <Package className="w-12 h-12 mb-3 opacity-20" />
            <p className="text-sm font-medium text-center">No hay pedidos en esta pestaña</p>
          </div>
        )}

        {filteredOrders.map((order) => (
          <div
            key={order.id}
            className="bg-surface-dark rounded-2xl overflow-hidden border border-border-dark flex flex-col"
          >
            {/* Context Color Band */}
            <div
              className={`h-1.5 w-full ${
                order.status === 'pending'
                  ? 'bg-red-500 shadow-[0_0_15px_rgba(239,68,68,0.4)]'
                  : order.status === 'preparing'
                    ? 'bg-orange-400'
                    : order.status === 'ready'
                      ? 'bg-green-500 shadow-[0_0_15px_rgba(34,197,94,0.4)]'
                      : 'bg-slate-600'
              }`}
            ></div>

            <div className="p-4 flex-1 flex flex-col">
              <div className="flex justify-between items-start mb-3">
                <div className="pr-4 border-r border-border-dark/50 mr-4">
                  <h3 className="text-xl font-black text-white leading-tight tracking-tight mb-1">
                    {order.customer_name}
                  </h3>
                  <p className="text-xs text-text-muted font-mono bg-background-dark/50 px-2 py-0.5 rounded-md inline-block">
                    {new Date(order.created_at).toLocaleTimeString([], {
                      hour: '2-digit',
                      minute: '2-digit'
                    })}
                  </p>
                </div>

                <div className="flex flex-col items-end gap-1.5 min-w-[80px]">
                  <span className="bg-primary/10 text-primary border border-primary/20 text-[10px] font-black px-2 py-1 rounded-full uppercase tracking-wider">
                    {order.status}
                  </span>
                  {order.total_amount && (
                    <span className="text-sm font-bold text-green-400 mt-1">
                      ${order.total_amount}
                    </span>
                  )}
                </div>
              </div>

              <div className="text-sm text-text-secondary bg-background-dark/30 p-3 rounded-xl mb-auto border border-white/5">
                <p className="flex items-start gap-2">
                  <span className="material-symbols-outlined text-base mt-0.5 opacity-50">
                    location_on
                  </span>
                  {order.address_text || 'Retiro en Local'}
                </p>
              </div>

              {/* Order Actions */}
              <div className="border-t border-border-dark mt-4 pt-4 flex gap-3">
                {activeTab === 'pending' && (
                  <>
                    {order.status === 'pending' ? (
                      <button
                        onClick={() => handleUpdateStatus(order.id, 'preparing')}
                        disabled={updateStatusMutation.isPending}
                        className="flex-1 h-12 rounded-xl border border-border-dark text-white font-bold text-sm hover:bg-white/5 transition-colors flex items-center justify-center gap-2"
                      >
                        <ChefHat className="w-4 h-4 text-text-muted" /> Olla a fuego
                      </button>
                    ) : (
                      <button
                        disabled
                        className="flex-1 h-12 rounded-xl bg-background-dark text-text-secondary font-bold text-sm cursor-not-allowed opacity-50 flex items-center justify-center gap-2 border border-border-dark"
                      >
                        <div className="w-2 h-2 rounded-full bg-orange-400 animate-pulse"></div>
                        En preparación
                      </button>
                    )}
                    <button
                      onClick={() => handleUpdateStatus(order.id, 'ready')}
                      disabled={updateStatusMutation.isPending}
                      className="flex-1 h-12 rounded-xl bg-primary text-white font-bold text-sm hover:bg-orange-600 transition-colors shadow-lg shadow-primary/20 flex items-center justify-center gap-2"
                    >
                      <CheckCircle2 className="w-4 h-4" /> ¡Está Listo!
                    </button>
                  </>
                )}

                {activeTab === 'ready' && (
                  <button
                    onClick={() => handleUpdateStatus(order.id, 'shipping')}
                    disabled={updateStatusMutation.isPending}
                    className="w-full h-12 rounded-xl bg-green-500 text-white font-bold text-sm hover:bg-green-600 transition-colors shadow-[0_0_20px_rgba(34,197,94,0.3)] flex items-center justify-center gap-2"
                  >
                    <Package className="w-4 h-4" /> Despachar Delivery
                  </button>
                )}

                {activeTab === 'history' && (
                  <button
                    disabled
                    className="w-full h-12 rounded-xl bg-background-dark border border-border-dark text-text-muted font-bold text-sm cursor-not-allowed flex items-center justify-center gap-2"
                  >
                    Cerrado / Finalizado
                  </button>
                )}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  )
}
